// Check whether social story delivery is enabled for any of X, Telegram, Discord.
// Filter to story-eligible alerts (importance_score >= threshold).

const enableX        = ($vars.ENABLE_SOCIAL_X        || '').toLowerCase() === 'true';
const enableTelegram = ($vars.ENABLE_SOCIAL_TELEGRAM  || '').toLowerCase() === 'true';
const enableDiscord  = ($vars.ENABLE_SOCIAL_DISCORD   || '').toLowerCase() === 'true';

const anyEnabled = enableX || enableTelegram || enableDiscord;

if (!anyEnabled) {
  return [{ json: { _social_skip: true, reason: 'No social channels enabled for story delivery' } }];
}

const threshold = parseInt($vars.SOCIAL_ALERT_STORY_THRESHOLD || $vars.META_ALERT_STORY_THRESHOLD || '80', 10);

const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];

// Filter to high-importance alerts already approved for delivery
const eligible = items.filter(i =>
  i.importance_score >= threshold &&
  ((i.channels || []).includes('telegram') || (i.channels || []).includes('discord'))
);

if (eligible.length === 0) {
  return [{ json: { _social_skip: true, reason: `No alerts met story threshold (>= ${threshold})` } }];
}

return eligible.map(item => ({
  json: {
    ...item,
    _social_enable_x:        enableX,
    _social_enable_telegram: enableTelegram,
    _social_enable_discord:  enableDiscord,
    _social_skip: false
  }
}));

// Format the alert as a social content asset for X, Telegram, and Discord.
const item = $input.item.json;

const topicEmoji = {
  crypto: '🪙', finance: '📈', economy: '🏦',
  health: '🏥', ai: '🤖', energy: '⚡', technology: '💻'
};
const discordColor = {
  crypto: 0xF7931A, finance: 0x2ECC71, economy: 0x3498DB,
  health: 0xE74C3C, ai: 0x9B59B6, energy: 0xF1C40F, technology: 0x1ABC9C
};

const emoji = topicEmoji[item.topic_slug] || '📰';
const topicLabel = (item.topic_slug || '').charAt(0).toUpperCase() + (item.topic_slug || '').slice(1);
const color = discordColor[item.topic_slug] || 0x95A5A6;
const dateKey = item.event_at ? item.event_at.slice(0, 10) : new Date().toISOString().slice(0, 10);
const timestamp = new Date().toISOString();

const truncate = (s, n) => s && s.length > n ? s.slice(0, n - 1) + '…' : (s || '');
const escHtml = (s) => (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
const headline = item.headline || '';
const summaryText = item.summary_text || '';

// ── X alert post ──
const xAlertFull = `${emoji} ${headline}`;
const xSourceSuffix = item.source_url ? `\n\n${item.source_url}` : '';
const xAlertText = (xAlertFull + xSourceSuffix).length <= 280
  ? xAlertFull + xSourceSuffix
  : truncate(xAlertFull, 280 - xSourceSuffix.length) + xSourceSuffix;

// ── Telegram alert HTML ──
const importanceScore = item.importance_score || 0;
const importanceSegments = Math.max(0, Math.min(5, Math.round(importanceScore / 20)));
const importanceBar = '🟩'.repeat(importanceSegments) + '⬜'.repeat(5 - importanceSegments);
const sourceLink = item.source_url
  ? `\n<a href="${escHtml(item.source_url)}">Source: ${escHtml(item.source_name || 'Unknown')}</a>`
  : `\nSource: ${escHtml(item.source_name || 'Unknown')}`;
const telegramAlert = [
  `${emoji} <b>${escHtml((item.topic_slug || '').toUpperCase())}</b>  |  Importance: ${importanceBar} ${item.importance_score}/100`,
  '',
  `<b>${escHtml(headline)}</b>`,
  '',
  escHtml(summaryText),
  sourceLink
].join('\n');

// ── Discord alert embed ──
const tsRaw = item.event_at;
const embedTimestamp = (tsRaw && !isNaN(Date.parse(tsRaw))) ? tsRaw : timestamp;
const discordAlertEmbed = {
  title: `${emoji} ${headline.slice(0, 252)}`,
  description: summaryText.slice(0, 4096),
  color,
  fields: [
    { name: 'Topic', value: topicLabel, inline: true },
    { name: 'Importance', value: `${item.importance_score}/100`, inline: true },
    { name: 'Severity', value: `${item.severity_score}/100`, inline: true }
  ],
  footer: { text: item.source_name || 'Unknown' },
  timestamp: embedTimestamp
};
if (item.source_url) discordAlertEmbed.url = item.source_url;

const enableX        = !!item._social_enable_x;
const enableTelegram = !!item._social_enable_telegram;
const enableDiscord  = !!item._social_enable_discord;

const storyAsset = {
  topic_slug:     item.topic_slug,
  date_key:       dateKey,
  asset_type:     'story',
  source_type:    'alert',
  source_id:      item.item_id || item.alert_id?.toString() || null,
  publish_job_id: null,
  ai_output: {
    post_caption:          summaryText || headline,
    hashtags:              [`#${item.topic_slug}`, '#breakingnews', '#newsupdate'],
    image_prompt:          `Urgent news background for ${item.topic_slug} story`,
    story_caption:         truncate(`${emoji} ${headline}`, 200),
    story_background_hint: `High-impact ${item.topic_slug} news visual`,
    cta:                   null
  },
  x: {
    enabled:    enableX,
    post_text:  xAlertText,
    thread:     null,
    alert_text: xAlertText
  },
  telegram: {
    enabled:      enableTelegram,
    message_html: telegramAlert,
    alert_html:   telegramAlert
  },
  discord: {
    enabled:     enableDiscord,
    embed:       discordAlertEmbed,
    alert_embed: discordAlertEmbed
  },
  generated_at: timestamp
};

return [{ json: storyAsset }];

// Expand each story asset into per-platform delivery tasks.
// One failure should not block delivery to other platforms.
const asset = $input.item.json;
const tasks = [];

if (asset.x && asset.x.enabled) {
  tasks.push({
    platform:   'x',
    post_type:  'alert',
    post_text:  asset.x.alert_text || asset.x.post_text,
    topic_slug: asset.topic_slug,
    date_key:   asset.date_key,
    source_id:  asset.source_id
  });
}

if (asset.telegram && asset.telegram.enabled) {
  tasks.push({
    platform:     'telegram',
    post_type:    'alert',
    message_html: asset.telegram.alert_html || asset.telegram.message_html,
    topic_slug:   asset.topic_slug,
    date_key:     asset.date_key,
    source_id:    asset.source_id
  });
}

if (asset.discord && asset.discord.enabled) {
  tasks.push({
    platform:   'discord',
    post_type:  'embed',
    embed:      asset.discord.alert_embed || asset.discord.embed,
    topic_slug: asset.topic_slug,
    date_key:   asset.date_key,
    source_id:  asset.source_id
  });
}

if (tasks.length === 0) {
  return [{ json: {
    _social_skip: true,
    reason: 'No enabled social channels for this alert',
    topic_slug: asset.topic_slug,
    source_id:  asset.source_id
  } }];
}

return tasks.map(t => ({ json: t }));

// Resolve API endpoint per platform.
const task = $input.item.json;

if (task.platform === 'x') {
  const xBearerToken = $vars.SOCIAL_X_BEARER_TOKEN || null;
  if (!xBearerToken) {
    return [{ json: { ...task, _api_skip: true, error_message: 'Missing SOCIAL_X_BEARER_TOKEN' } }];
  }
  return [{ json: {
    ...task,
    _api_url:     'https://api.twitter.com/2/tweets',
    _api_method:  'POST',
    _api_headers: { 'Authorization': `Bearer ${xBearerToken}`, 'Content-Type': 'application/json' },
    _api_body:    { text: task.post_text }
  } }];
}

if (task.platform === 'telegram') {
  const botToken = $vars.SOCIAL_TELEGRAM_BOT_TOKEN || $vars.TELEGRAM_BOT_TOKEN || null;
  const chatId   = $vars.SOCIAL_TELEGRAM_CHAT_ID   || $vars.TELEGRAM_CHAT_ID   || null;
  if (!botToken || !chatId) {
    return [{ json: { ...task, _api_skip: true, error_message: 'Missing Telegram bot token or chat ID' } }];
  }
  return [{ json: {
    ...task,
    _api_url:     `https://api.telegram.org/bot${botToken}/sendMessage`,
    _api_method:  'POST',
    _api_headers: { 'Content-Type': 'application/json' },
    _api_body:    { chat_id: chatId, text: task.message_html, parse_mode: 'HTML', disable_web_page_preview: false }
  } }];
}

if (task.platform === 'discord') {
  const webhookUrl = $vars.SOCIAL_DISCORD_WEBHOOK_URL || $vars.DISCORD_WEBHOOK_URL || null;
  if (!webhookUrl) {
    return [{ json: { ...task, _api_skip: true, error_message: 'Missing Discord webhook URL' } }];
  }
  return [{ json: {
    ...task,
    _api_url:     webhookUrl,
    _api_method:  'POST',
    _api_headers: { 'Content-Type': 'application/json' },
    _api_body:    { embeds: [task.embed] }
  } }];
}

return [{ json: { ...task, _api_skip: true, error_message: `Unknown platform: ${task.platform}` } }];

// Skipped — missing credentials. Log as 'skipped' in D1.
const task = $input.item.json;
return [{ json: {
  platform:         task.platform,
  post_type:        task.post_type,
  topic_slug:       task.topic_slug,
  date_key:         task.date_key,
  source_id:        task.source_id,
  status:           'skipped',
  platform_post_id: null,
  error_message:    task.error_message || 'Missing API credentials'
} }];

// Handle API response.
const response = $input.item.json;
const task     = $('Resolve API Endpoint').item.json;

const statusCode = response._statusCode || response.statusCode || null;
const hasError = !!response.error || !!response.errors || (statusCode && statusCode >= 400);

if (hasError) {
  const errMsg = response.error
    ? (typeof response.error === 'string' ? response.error : JSON.stringify(response.error).slice(0, 300))
    : response.errors
      ? JSON.stringify(response.errors).slice(0, 300)
      : `HTTP ${statusCode}`;
  return [{ json: {
    platform:         task.platform,
    post_type:        task.post_type,
    topic_slug:       task.topic_slug,
    date_key:         task.date_key,
    source_id:        task.source_id,
    status:           'failed',
    platform_post_id: null,
    error_message:    errMsg
  } }];
}

let postId = null;
if (task.platform === 'x') postId = response.data?.id || response.id || null;
else if (task.platform === 'telegram') postId = response.result?.message_id?.toString() || null;
else if (task.platform === 'discord') postId = response.id || null;

return [{ json: {
  platform:         task.platform,
  post_type:        task.post_type,
  topic_slug:       task.topic_slug,
  date_key:         task.date_key,
  source_id:        task.source_id,
  status:           'published',
  platform_post_id: postId
} }];

// Build D1 log entry for social_publish_log.
const r = $input.item.json;
const attempt = Number.isFinite(Number(r.attempt)) ? Number(r.attempt) : 1;
return [{ json: {
  _d1_sql: `INSERT INTO social_publish_log
    (topic_slug, date_key, asset_type, source_type, source_id, platform, post_type,
     status, platform_post_id, error_message, attempt, created_at, updated_at)
  VALUES (?, ?, 'story', 'alert', ?, ?, ?, ?, ?, ?, ?,
    strftime('%Y-%m-%dT%H:%M:%SZ','now'),
    strftime('%Y-%m-%dT%H:%M:%SZ','now')
  )`,
  _d1_params: [
    r.topic_slug,
    r.date_key,
    r.source_id || null,
    r.platform,
    r.post_type || 'alert',
    r.status || 'published',
    r.platform_post_id || null,
    r.error_message || null,
    attempt
  ],
  ...r,
  attempt
} }];
